question.en:
Which code snippet correctly demonstrates the Dependency Inversion Principle in practice?
typescript
// Option A
class UserService {
  private db: MySQLDatabase = new MySQLDatabase();
  getUser(id: string) { return this.db.query(...); }
}

// Option B
interface UserRepository {
  getUser(id: string): Promise<User>;
}
class UserService {
  constructor(private repo: UserRepository) {}
  getUser(id: string) { return this.repo.getUser(id); }
}

// Option C
class UserService {
  getUser(id: string) {
    const repo = new PostgresRepository();
    return repo.getUser(id);
  }
}

// Option D
class UserService {
  private static repo: any;
  constructor() { UserService.repo = new MongoRepository(); }
  getUser(id: string) { return UserService.repo.getUser(id); }
}

